import React, { useState } from 'react';




export function PlanTrip() {
  // State for Destination and From inputs
  const [destination, setDestination] = useState('');
  const [from, setFrom] = useState('');

  // State for Days input
  const [days, setDays] = useState('');

  // Handle change for Destination input
  const handleDestinationChange = (event) => {
    setDestination(event.target.value);
  };

  // Handle change for From input
  const handleFromChange = (event) => {
    setFrom(event.target.value);
  };

  // Handle change for Days input
  const handleDaysChange = (event) => {
    const value = event.target.value;

    // Ensure only numbers are entered
    if (/^\d*$/.test(value)) {
      setDays(value);
    }
  };

  return (
    <div className='py-4 w-11/12 mx-auto'>
      {/* Text Inputs for Destination and From */}
      <h1>Enter Trip Details</h1>

      <div className='flex flex-col py-4'>
       <label>Going to  <input
          type="text"
          value={destination}
          onChange={handleDestinationChange}
          placeholder="Destination to...."
          required
        /></label>
      </div>
      <div>
        <input
          type="text"
          value={from}
          onChange={handleFromChange}
          placeholder="From...."
          required
        />
      </div>
      <div>
        <p>Destination: {destination}</p>
        <p>From: {from}</p>
      </div>

      {/* Number of Days Input */}
      <div>
        <h2>Enter the Number of Days</h2>
        <input
          type="text"
          value={days}
          onChange={handleDaysChange}
          placeholder="Enter number of days"
        />
        <p>You entered: {days ? days : 'No days entered'}</p>
      </div>
    </div>
  );
}
